export default function CategoryTabs({ categorias, selected, onSelect }) { return <div id="categorias" className="no-scrollbar flex gap-3 overflow-x-auto py-2">{[{id:'all', nombre:'Todos', icono:'✨'}, ...categorias].map(cat => <button key={cat.id} onClick={()=>onSelect(cat.id)} className={`min-w-max rounded-full px-5 py-3 text-sm font-bold transition ${selected===cat.id ? 'bg-ink text-white shadow-premium' : 'bg-white text-black/70 hover:bg-black/5'}`}>{cat.icono} {cat.nombre}</button>)}</div>; }
