import { X } from 'lucide-react';
import { useStore } from '../../context/StoreContext';
import { currency, safeArray } from '../../utils/format';
export default function QuickViewModal() { const { quickView: p, setQuickView, addToCart, productos } = useStore(); if (!p) return null; const related = productos.filter(x => x.id !== p.id && x.categoria_id === p.categoria_id).slice(0,3); return <div className="fixed inset-0 z-50 grid place-items-center bg-black/45 p-4 backdrop-blur-sm" onClick={()=>setQuickView(null)}><div className="max-h-[92vh] w-full max-w-5xl overflow-y-auto rounded-[2rem] bg-white shadow-premium" onClick={e=>e.stopPropagation()}><div className="grid gap-6 p-5 md:grid-cols-2"><div className="grid gap-3">{safeArray(p.imagenes).concat(p.imagen_principal).slice(0,3).map((img,i)=><img key={`${img}-${i}`} src={img} alt={p.nombre} className="aspect-square w-full rounded-[1.5rem] object-cover"/>).slice(0,1)}</div><div className="p-2 md:p-5"><button className="float-right rounded-full bg-mist p-2" onClick={()=>setQuickView(null)}><X/></button><p className="admin-label">{p.marca}</p><h2 className="mt-2 text-3xl font-black">{p.nombre}</h2><p className="mt-4 text-black/60">{p.descripcion}</p><p className="mt-5 text-3xl font-black">{currency(p.precio)}</p><p className="mt-2 text-sm font-semibold">Stock: {p.stock > 0 ? p.stock : 'Agotado'}</p><button className="btn-primary mt-6 w-full" disabled={p.stock<=0} onClick={()=>addToCart(p)}>Añadir al carrito</button><h3 className="mt-8 font-black">Relacionados</h3><div className="mt-3 grid gap-2">{related.map(r=><button key={r.id} className="rounded-2xl bg-mist p-3 text-left text-sm font-semibold" onClick={()=>setQuickView(r)}>{r.nombre}</button>)}</div></div></div></div></div>; }
