import { Eye, Heart, ShoppingBag } from 'lucide-react';
import { Link } from 'react-router-dom';
import { useStore } from '../../context/StoreContext';
import { currency, discountPercent } from '../../utils/format';
export default function ProductCard({ product }) { const { addToCart, favorites, toggleFavorite, setQuickView } = useStore(); const off = discountPercent(product.precio, product.precio_anterior); const soldOut = product.stock <= 0; return <article className="group overflow-hidden rounded-[2rem] bg-white shadow-sm transition duration-300 hover:-translate-y-1 hover:shadow-premium"><div className="relative aspect-[4/5] overflow-hidden bg-platinum"><Link to={`/producto/${product.id}`}><img src={product.imagen_principal} alt={product.nombre} loading="lazy" className="h-full w-full object-cover transition duration-700 group-hover:scale-110"/></Link><div className="absolute left-3 top-3 flex flex-wrap gap-2">{product.nuevo && <Badge>Nuevo</Badge>}{product.oferta && <Badge>Oferta</Badge>}{product.destacado && <Badge>Top</Badge>}{soldOut && <Badge>Agotado</Badge>}{off>0 && <Badge>-{off}%</Badge>}</div><button onClick={()=>toggleFavorite(product.id)} className="absolute right-3 top-3 rounded-full bg-white/80 p-2 backdrop-blur hover:bg-white"><Heart className={`h-5 w-5 ${favorites.includes(product.id) ? 'fill-ink' : ''}`}/></button></div><div className="p-5"><p className="text-xs font-bold uppercase tracking-widest text-black/40">{product.marca}</p><Link to={`/producto/${product.id}`} className="mt-1 block text-lg font-bold hover:underline">{product.nombre}</Link><div className="mt-3 flex items-end gap-2"><span className="text-xl font-black">{currency(product.precio)}</span>{product.precio_anterior && <span className="text-sm text-black/40 line-through">{currency(product.precio_anterior)}</span>}</div><div className="mt-5 grid grid-cols-[1fr_auto] gap-2"><button disabled={soldOut} onClick={()=>addToCart(product)} className="btn-primary disabled:cursor-not-allowed disabled:bg-black/20"><ShoppingBag className="mr-2 h-4 w-4"/>Añadir</button><button onClick={()=>setQuickView(product)} className="btn-secondary px-4"><Eye className="h-4 w-4"/></button></div></div></article>; }
function Badge({children}) { return <span className="rounded-full bg-white/86 px-3 py-1 text-[11px] font-black uppercase tracking-wider backdrop-blur">{children}</span>; }
