import { useParams } from 'react-router-dom';
import ProductGrid from '../components/product/ProductGrid';
import Seo from '../components/common/Seo';
import { useStore } from '../context/StoreContext';
import { currency, safeArray } from '../utils/format';
export default function ProductPage() { const { id } = useParams(); const { productos, addToCart } = useStore(); const p = productos.find(x=>String(x.id)===String(id)); if (!p) return <section className="section min-h-screen pt-32"><h1 className="text-3xl font-black">Producto no encontrado</h1></section>; const related = productos.filter(x=>x.id!==p.id && x.categoria_id===p.categoria_id).slice(0,4); return <section className="section min-h-screen pt-32"><Seo title={p.nombre} description={p.descripcion}/><div className="grid gap-10 lg:grid-cols-2"><div className="grid gap-4 sm:grid-cols-2">{[p.imagen_principal, ...safeArray(p.imagenes)].filter(Boolean).slice(0,4).map((img,i)=><img key={`${img}-${i}`} src={img} alt={p.nombre} className="aspect-square rounded-[2rem] object-cover shadow-sm transition hover:scale-[1.02]"/>)}</div><div className="lg:sticky lg:top-32 lg:h-max"><p className="admin-label">{p.marca}</p><h1 className="mt-3 text-5xl font-black">{p.nombre}</h1><p className="mt-5 text-black/60">{p.descripcion}</p><div className="mt-6 text-4xl font-black">{currency(p.precio)}</div><div className="mt-6 rounded-[2rem] bg-white p-5"><h2 className="font-black">Especificaciones</h2><ul className="mt-3 space-y-2 text-sm text-black/60"><li>Stock: {p.stock}</li><li>Categoría ID: {p.categoria_id}</li><li>Subcategoría ID: {p.subcategoria_id}</li><li>Estado: {p.oferta ? 'Oferta' : 'Precio regular'}</li></ul></div><button disabled={p.stock<=0} onClick={()=>addToCart(p)} className="btn-primary mt-6 w-full disabled:bg-black/20">Añadir al carrito</button></div></div><div className="mt-20"><h2 className="mb-6 text-3xl font-black">Productos relacionados</h2><ProductGrid products={related}/></div></section>; }
