import { useStore } from '../../context/StoreContext';
export default function PromoBanner() { const { productos } = useStore(); const count = productos.filter(p=>p.oferta).length; return <section className="section -mt-10 relative z-10"><div className="glass grid gap-4 rounded-[2rem] p-6 shadow-premium md:grid-cols-3 md:items-center"><div className="md:col-span-2"><p className="text-sm font-bold uppercase tracking-[.22em] text-black/45">Banner administrable</p><h2 className="mt-2 text-2xl font-black">Ofertas y novedades sincronizadas automáticamente</h2></div><a href="#ofertas" className="btn-primary justify-self-start md:justify-self-end">{count} ofertas activas</a></div></section>; }
